async function dlD(){var btn=document.getElementById('dlBtn'),st=document.getElementById('st');
btn.disabled=true;btn.textContent='Compiling...';
try{if(typeof docx==='undefined'){st.textContent='Loading library...';
await new Promise(function(res,rej){var s=document.createElement('script');s.src='https://cdn.jsdelivr.net/npm/docx@8.5.0/build/index.umd.js';s.onload=res;s.onerror=function(){rej(new Error('docx.js failed to load'));};document.head.appendChild(s);});}
st.textContent='Building document...';await new Promise(function(r){setTimeout(r,200);});
var doc=await buildDocx();st.textContent='Packaging...';
var blob=await docx.Packer.toBlob(doc);
var t=(document.getElementById('docTitle').innerText||'Document').replace(/[^a-zA-Z0-9]/g,'_');
saveAs(blob,'WPP_'+t+'.docx');
st.textContent='\u2705 Download complete!';}catch(e){st.textContent='Error: '+e.message;console.error(e);}
btn.disabled=false;btn.textContent='\u2B07 DOWNLOAD DOCX';}

